const input = $input.first().json;

if (!input.jobId) throw new Error('jobId ausente');
if (!input.projectId) throw new Error('projectId ausente');
if (!input.callbacks?.successUrl || !input.callbacks?.failureUrl || !input.callbacks?.token) {
  throw new Error('callbacks incompletos');
}
if (!input.productContext?.productName) throw new Error('productContext.productName ausente');

return [{
  json: {
    ...input,
    sourceImages: Array.isArray(input.sourceImages) ? input.sourceImages : [],
    targetMarketplaces: Array.isArray(input.productContext?.targetMarketplaces)
      ? input.productContext.targetMarketplaces.join(', ')
      : '',
  }
}];

const data = $input.first().json;
const ctx = data.productContext;
const imageLines = (data.sourceImages || []).map((img, index) => `Imagem ${index + 1}: ${img.fileUrl}`).join('
');

const combinedPrompt = `Use as imagens de referencia enviadas pelo usuario para recriar fielmente o produto "${ctx.productName}" e gerar variacoes profissionais para marketplace.

Dados do produto:
- Categoria: ${ctx.category || ''}
- Contexto: ${ctx.shortContext || ''}
- Cor: ${ctx.color || ''}
- Material: ${ctx.material || ''}
- Dimensoes: ${ctx.dimensionsXcm || ''} cm x ${ctx.dimensionsYcm || ''} cm x ${ctx.dimensionsZcm || ''} cm

Imagens de referencia:
${imageLines || 'Nenhuma imagem informada'}

Gere exatamente 3 imagens quadradas em alta qualidade:
1. Uma imagem de capa com fundo branco neutro
2. Uma imagem com indicacao de medidas visuais
3. Uma imagem lifestyle mostrando uso real do produto

Regras obrigatorias:
- preservar o formato e os detalhes do produto original
- sem texto promocional
- sem logo
- sem marca d'agua
- composicao profissional
- alta resolucao
- foco total no produto`;

return [{
  json: {
    ...data,
    imageProviderBody: {
      model: $env.IMAGE_PROVIDER_MODEL || 'gpt-image-1',
      prompt: combinedPrompt,
      size: '1024x1024',
      n: 3,
      sourceImages: data.sourceImages.map((img) => img.fileUrl),
    }
  }
}];

const previous = $items('Build Image Prompt', 0, 0)[0].json;
const response = $input.first().json;

function failurePayload(message) {
  return [{
    json: {
      callbackUrl: previous.callbacks.failureUrl,
      callbackToken: previous.callbacks.token,
      callbackPayload: {
        jobId: previous.jobId,
        jobType: 'image_generation',
        provider: $env.IMAGE_PROVIDER_MODEL || 'image-provider',
        errorCode: 'IMAGE_GENERATION_FAILED',
        errorMessage: message,
      }
    }
  }];
}

if (response.error) {
  return failurePayload(typeof response.error === 'string' ? response.error : JSON.stringify(response.error));
}

const rawImages = response.images || response.data || response.result?.images || response.output || [];
if (!Array.isArray(rawImages) || rawImages.length === 0) {
  return failurePayload('Provider de imagem nao retornou imagens em formato reconhecido');
}

function resolveUrl(item) {
  if (!item) return null;
  if (typeof item === 'string') return item;
  if (item.url) return item.url;
  if (item.fileUrl) return item.fileUrl;
  if (item.image_url) return item.image_url;
  if (item.b64_json) return `data:image/png;base64,${item.b64_json}`;
  if (item.output?.url) return item.output.url;
  return null;
}

const definitions = [
  { kind: 'white_background', title: 'Catalogo' },
  { kind: 'dimensions', title: 'Dimensoes' },
  { kind: 'lifestyle', title: 'Lifestyle' },
];

const images = rawImages.slice(0, 3).map((item, index) => {
  const url = resolveUrl(item);
  return {
    imageKind: definitions[index]?.kind || 'lifestyle',
    title: definitions[index]?.title || `Imagem ${index + 1}`,
    fileUrl: url,
    storageKey: `projects/${previous.projectId}/results/${definitions[index]?.kind || `image-${index + 1}`}.png`,
    width: 1024,
    height: 1024,
    variationIndex: index + 1,
  };
}).filter((item) => !!item.fileUrl);

if (!images.length) {
  return failurePayload('Nao foi possivel extrair URLs ou imagens validas da resposta do provider');
}

return [{
  json: {
    callbackUrl: previous.callbacks.successUrl,
    callbackToken: previous.callbacks.token,
    callbackPayload: {
      jobId: previous.jobId,
      jobType: 'image_generation',
      provider: $env.IMAGE_PROVIDER_MODEL || 'image-provider',
      result: {
        images,
      }
    }
  }
}];
